    public function handle_order_book(Client $client, $message) {
        //
        // {
        //     "asks" => array(
        //       array()
        //     ),
        //     "bids" => array(
        //       array()
        //     ),
        //     "datetime" => "string",
        //     "nonce" => 9007199254740991,
        //     "symbol" => "string",
        //     "timestamp" => 9007199254740991
        // }
        //
        $symbol = $this->safe_string($message, 'symbol');
        $market = $this->market($symbol);
        $topic = $market['id'] . '@orderbook';
        if (!(is_array($this->orderbooks) && array_key_exists($symbol, $this->orderbooks))) {
            $defaultLimit = $this->safe_integer($this->options, 'watchOrderBookLimit', 1000);
            $subscription = $client->subscriptions[$topic];
            $limit = $this->safe_integer($subscription, 'limit', $defaultLimit);
            $this->orderbooks[$symbol] = $this->order_book(array(), $limit);
            $subscription['limit'] = $limit;
            $this->spawn(array($this, 'fetch_order_book_snapshot'), $client, $message, $subscription);
        } else {
            $orderbook = $this->orderbooks[$symbol];
            $prevNonce = $this->safe_integer($orderbook, 'nonce');
            $nonce = $this->safe_integer($message, 'nonce');
            if ($nonce === ($prevNonce + 1)) {
                $this->handle_order_book_message($client, $message, $orderbook);
                $client->resolve ($orderbook, $topic);
            }
        }
    }

    public function fetch_order_book_snapshot($client, $message, $subscription) {
        return Async\async(function () use ($client, $message, $subscription) {
            $symbol = $this->safe_string($message, 'symbol');
            $market = $this->market($symbol);
            $messageHash = $market['id'] . '@orderbook';
            try {
                $defaultLimit = $this->safe_integer($this->options, 'watchOrderBookLimit', 1000);
                $limit = $this->safe_integer($subscription, 'limit', $defaultLimit);
                $params = $this->safe_dict($subscription, 'params');
                $snapshot = Async\await($this->fetch_rest_order_book_safe($symbol, $limit, $params));
                if ($this->safe_value($this->orderbooks, $symbol) === null) {
                    // if the $orderbook is dropped before the $snapshot is received
                    return;
                }
                $orderbook = $this->orderbooks[$symbol];
                $orderbook->reset ($snapshot);
                $this->orderbooks[$symbol] = $orderbook;
                $client->resolve ($orderbook, $messageHash);
            } catch (Exception $e) {
                unset($client->subscriptions[$messageHash]);
                $client->reject ($e, $messageHash);
            }
        }) ();
    }

    public function handle_order_book_message(Client $client, $message, $orderbook) {
        $this->handle_deltas($orderbook['asks'], $this->safe_value($message, 'asks', array()));
        $this->handle_deltas($orderbook['bids'], $this->safe_value($message, 'bids', array()));
        $timestamp = $this->safe_integer($message, 'timestamp');
        $nonce = $this->safe_integer($message, 'nonce');
        $orderbook['timestamp'] = $timestamp;
        $orderbook['datetime'] = $this->iso8601($timestamp);
        $orderbook['nonce'] = $nonce;
        return $orderbook;
    }

    public function handle_delta($bookside, $delta) {
        $price = $this->safe_float_2($delta, 'price', 0);
        $amount = $this->safe_float_2($delta, 'quantity', 1);
        $bookside->store ($price, $amount);
    }

    public function handle_deltas($bookside, $deltas) {
        for ($i = 0; $i < count($deltas); $i++) {
            $this->handle_delta($bookside, $deltas[$i]);
        }
    }

    public function watch_positions(?array $symbols = null, ?int $since = null, ?int $limit = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($symbols, $since, $limit, $params) {
            /**
             *
             * @see https://testnet.aftermath.finance/docs/#/CCXT/service%3A%3Ahandlers%3A%3Accxt%3A%3Astream%3A%3Apositions
             *
             * watch all open positions
             * @param {string[]|null} $symbols list of unified market $symbols
             * @param {int} [$since] the earliest time in ms to fetch positions for
             * @param {int} [$limit] the maximum number of position structures to retrieve
             * @param {array} $params extra parameters specific to the exchange API endpoint
             * @param {int} [$params->accountNumber] account number to query orders for, required
             * @return {array[]} a list of {@link https://docs.ccxt.com/en/latest/manual.html#position-structure position structure}
             */
            Async\await($this->load_markets());
            $messageHashes = array();
            $symbols = $this->market_symbols($symbols);
            if (!$this->is_empty($symbols)) {
                for ($i = 0; $i < count($symbols); $i++) {
                    $symbol = $symbols[$i];
                    $messageHashes[] = 'positions::' . $symbol;
                }
            } else {
                $messageHashes[] = 'positions';
            }
            $accountNumber = $this->safe_number($params, 'accountNumber');
            $request = array(
                'accountNumber' => $accountNumber,
            );
            $message = $this->extend($request, $params);
            $suffix = 'positions';
            $url = $this->urls['api']['ws']['swap'] . '/' . $suffix;
            $client = $this->client($url);
            $this->set_positions_cache($client, $symbols, $params);
            $fetchPositionsSnapshot = $this->handle_option('watchPositions', 'fetchPositionsSnapshot', true);
            $awaitPositionsSnapshot = $this->handle_option('watchPositions', 'awaitPositionsSnapshot', true);
            if ($fetchPositionsSnapshot && $awaitPositionsSnapshot && $this->positions === null) {
                $snapshot = Async\await($client->future ('fetchPositionsSnapshot'));
                return $this->filter_by_symbols_since_limit($snapshot, $symbols, $since, $limit, true);
            }
            $newPositions = Async\await($this->watch_public_multiple($suffix, $messageHashes, $message));
            if ($this->newUpdates) {
                return $newPositions;
            }
            return $this->filter_by_symbols_since_limit($this->positions, $symbols, $since, $limit, true);
        }) ();
    }

    public function set_positions_cache(Client $client, ?array $symbols = null, array $params = array ()) {
        $fetchPositionsSnapshot = $this->handle_option('watchPositions', 'fetchPositionsSnapshot', false);
        if ($fetchPositionsSnapshot) {
            $messageHash = 'fetchPositionsSnapshot';
            if (!(is_array($client->futures) && array_key_exists($messageHash, $client->futures))) {
                $client->future ($messageHash);
                $this->spawn(array($this, 'load_positions_snapshot'), $client, $messageHash, $symbols, $params);
            }
        } else {
            $this->positions = new ArrayCacheBySymbolBySide ();
        }
    }

    public function load_positions_snapshot($client, $messageHash, $symbols, $params) {
        return Async\async(function () use ($client, $messageHash, $symbols, $params) {
            $positions = Async\await($this->fetch_positions($symbols, $params));
            $this->positions = new ArrayCacheBySymbolBySide ();
            $cache = $this->positions;
            for ($i = 0; $i < count($positions); $i++) {
                $position = $positions[$i];
                $cache->append ($position);
            }
            // don't remove the $future from the .futures $cache
            $future = $client->futures[$messageHash];
            $future->resolve ($cache);
            $client->resolve ($cache, 'positions');
        }) ();
    }

    public function handle_positions($client, $message) {
        //
        // {
        //     "collateral" => 0.1,
        //     "contractSize" => 0.1,
        //     "contracts" => 0.1,
        //     "datetime" => "string",
        //     "entryPrice" => 0.1,
        //     "id" => "0x895037c09dd1025a136b5a5789c4ea2481176adf4c3b0c3521d5d2039bdfc3ba:123",
        //     "initialMargin" => 0.1,
        //     "initialMarginPercentage" => 0.1,
        //     "leverage" => 0.1,
        //     "liquidationPrice" => 0.1,
        //     "maintenanceMargin" => 0.1,
        //     "maintenanceMarginPercentage" => 0.1,
        //     "marginMode" => "cross",
        //     "marginRatio" => 0.1,
        //     "notional" => 0.1,
        //     "side" => "long",
        //     "symbol" => "BTC/USD:USDC",
        //     "timestamp" => 9007199254740991,
        //     "unrealizedPnl" => 0.1
        // }
        //
        if ($this->positions === null) {
            $this->positions = new ArrayCacheBySymbolBySide ();
        }
        $cache = $this->positions;
        $symbol = $this->safe_string($message, 'symbol');
        $market = $this->safe_market($symbol);
        $position = $this->parse_position($message, $market);
        $cache->append ($position);
        $messageHash = 'positions::' . $market['symbol'];
        $client->resolve ($position, $messageHash);
        $client->resolve (array( $position ), 'positions');
    }

    public function handle_error_message(Client $client, $message) {
        //
        // User $error => Expected Message::Text from $client, got Ping(b\"\")
        //
        if (gettype($message) === 'string') {
            if (mb_strpos($message, 'error') !== false) {
                try {
                    $feedback = $this->id . ' ' . $message;
                    $this->throw_exactly_matched_exception($this->exceptions['exact'], $message, $feedback);
                    throw new ExchangeError($message);
                } catch (Exception $error) {
                    if ($error instanceof AuthenticationError) {
                        $messageHash = 'authenticated';
                        $client->reject ($error, $messageHash);
                        if (is_array($client->subscriptions) && array_key_exists($messageHash, $client->subscriptions)) {
                            unset($client->subscriptions[$messageHash]);
                        }
                    } else {
                        $client->reject ($error);
                    }
                    return true;
                }
            }
        }
        return false;
    }

    public function handle_message(Client $client, $message) {
        if ($this->handle_error_message($client, $message)) {
            return;
        }
        // $methods = array(
        //     'trade' => array($this, 'handle_trade'),
        // );
        if (is_array($message) && array_key_exists('asks', $message)) {
            $this->handle_order_book($client, $message);
        } elseif (is_array($message) && array_key_exists('notional', $message)) {
            $this->handle_positions($client, $message);
        } else {
            $this->handle_trade($client, $message);
        }
    }
